387	export function forgetCommit(opts: {
388	  userId: number | string;
389	  query: string;
390	  expectedToken?: string;
391	}): {
392	  deleted: ForgetMatch[];
393	  wikiProtected: { match: ForgetMatch; referencedBy: string[] }[];
394	  remaining: number;
395	  shardSummary: { total: number; perTopic: Record<string, number> };
396	} {
397	  const { userId, query, expectedToken } = opts;
398	  const { matches, token } = forgetMatch(userId, query);
399	  if (matches.length === 0) {
400	    throw new Error(`no facts match query: ${JSON.stringify(query)}`);
401	  }
402	  if (expectedToken && expectedToken.trim() !== token) {
403	    throw new Error(
404	      `confirm token mismatch (got=${expectedToken}, expected=${token}); ` +
405	        `the master log changed since you previewed — call forget without ` +
406	        `confirm to re-preview.`
407	    );
408	  }
409	
410	  // Check wiki references — protect facts that are cited by wiki pages.
411	  const factIds = matches.map(m => extractFactId(m.line)).filter((id): id is string => !!id);
412	  const wikiRefs = checkWikiReferences(factIds);
413	  const wikiProtected: { match: ForgetMatch; referencedBy: string[] }[] = [];
414	  const deletable: ForgetMatch[] = [];
415	  for (const m of matches) {
416	    const id = extractFactId(m.line);
417	    if (id && wikiRefs[id]?.length) {
418	      wikiProtected.push({ match: m, referencedBy: wikiRefs[id] });
419	    } else {
420	      deletable.push(m);
421	    }
422	  }
423	
424	  // Rewrite master log with deletable indices stripped (wiki-protected kept).
425	  const master = masterFactsFile(userId);
426	  const allLines = readMasterLines(userId);
427	  const dropIdx = new Set(deletable.map((m) => m.index));
428	  const kept = allLines.filter((_, i) => !dropIdx.has(i));
429	
430	  // Safety gate 1: never write an empty file if the original had content.
431	  if (kept.length === 0 && allLines.length > 0) {
432	    throw new Error(
433	      `[forgetCommit] refuse to empty the master log ` +
434	        `(${allLines.length} lines would all be deleted). ` +
435	        `This is almost certainly a bug — aborting.`
436	    );
437	  }
438	
439	  // Safety gate 2: refuse to delete >50% of facts in a single operation.
440	  if (allLines.length > 0 && deletable.length > allLines.length * 0.5) {
441	    throw new Error(
442	      `[forgetCommit] refuse to delete ${deletable.length}/${allLines.length} facts ` +
443	        `(exceeds 50% threshold). Use smaller, more specific queries.`
444	    );
445	  }
446	
447	  // Safety: backup master log before rewrite.
448	  try {
449	    copyFileSync(master, `${master}.bak.${Date.now()}`);
450	  } catch {
451	    /* best-effort — don't block the operation if backup fails */
452	  }
453	
454	  writeFileSync(master, kept.join("\n") + (kept.length ? "\n" : ""), "utf8");
455	
456	  // Rebuild shards from the new master log so topic counts stay accurate
457	  // even if the same fact lived in multiple shards after a topics.json
458	  // edit (shouldn't happen with first-match-wins classify, but cheap
459	  // insurance).
460	  const shardSummary = rebuildShards(userId);
461	
462	  appendForgetLog({ userId, query, deleted: deletable, token });
463	
464	  return {
465	    deleted: deletable,
466	    wikiProtected,
467	    remaining: kept.length,
468	    shardSummary: { total: shardSummary.total, perTopic: shardSummary.perTopic },
